import React, { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { loginUser } from "../services/api";

function Login() {
  const navigate = useNavigate();

  const [formData, setFormData] = useState({ username: "", password: "" });
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  // ── DEMO ACCOUNTS (hardcode, không cần DB) ──────────────────
  const DEMO_ACCOUNTS = {
    testuser: {
      password: "123456",
      user: { id: 1, username: "testuser", role: "user",  email: "user@demo.com",  phone: "0901234567", player_id: 1 },
    },
    admin: {
      password: "admin123",
      user: { id: 2, username: "admin",    role: "admin", email: "admin@demo.com", phone: "0909999888", player_id: 2 },
    },
  };
  // ────────────────────────────────────────────────────────────

  const handleSubmit = async (e) => {
    e.preventDefault();
    setMessage("");
    setError("");

    if (!formData.username || !formData.password) {
      setError("Vui lòng nhập đầy đủ tên đăng nhập và mật khẩu.");
      return;
    }

    // Thử demo account trước (không cần DB)
    const demo = DEMO_ACCOUNTS[formData.username];
    if (demo && demo.password === formData.password) {
      localStorage.setItem("token", "demo-token-" + demo.user.role);
      localStorage.setItem("user", JSON.stringify(demo.user));
      setMessage("Đăng nhập thành công! Đang chuyển hướng...");
      setTimeout(() => navigate("/"), 600);
      return;
    }

    // Nếu không phải demo → thử gọi API thật
    setLoading(true);
    try {
      const result = await loginUser(formData);
      localStorage.setItem("token", result.token);
      localStorage.setItem("user", JSON.stringify(result.user));
      setMessage("Đăng nhập thành công! Đang chuyển hướng...");
      setTimeout(() => navigate("/"), 700);
    } catch (err) {
      setError("Sai tên đăng nhập hoặc mật khẩu.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-page">
      {/* LEFT — Branding */}
      <div className="auth-left">
        <Link to="/" className="auth-left-logo">
          <span className="auth-left-logo-mark">⚽</span>
          <span className="auth-left-logo-text">
            Đặt <span>Sân Bóng</span>
          </span>
        </Link>

        <div className="auth-left-body">
          <span className="auth-left-badge">🏆 Nền tảng bóng đá cộng đồng</span>
          <h1>Chào mừng bạn quay lại!</h1>
          <p>
            Đăng nhập để đặt sân, tham gia trận đấu, theo dõi lịch cá nhân
            và trải nghiệm đầy đủ tính năng của nền tảng bóng đá cộng đồng.
          </p>

          <div className="auth-features">
            <div className="auth-feature-item">
              <div className="auth-feature-icon">🏟️</div>
              <div className="auth-feature-text">
                <strong>Đặt sân nhanh chóng</strong>
                <span>Chọn sân, ngày, giờ chỉ trong vài bước đơn giản</span>
              </div>
            </div>
            <div className="auth-feature-item">
              <div className="auth-feature-icon">⚽</div>
              <div className="auth-feature-text">
                <strong>Tìm trận & kết nối đồng đội</strong>
                <span>Tham gia trận bóng cộng đồng, kết nối người chơi cùng trình độ</span>
              </div>
            </div>
            <div className="auth-feature-item">
              <div className="auth-feature-icon">📅</div>
              <div className="auth-feature-text">
                <strong>Quản lý lịch cá nhân</strong>
                <span>Theo dõi toàn bộ lịch đặt sân và trận đấu đã tham gia</span>
              </div>
            </div>
          </div>
        </div>

        <div className="auth-left-footer">
          © 2026 ĐặtSânBóng · Nền tảng bóng đá cộng đồng hiện đại
        </div>
      </div>

      {/* RIGHT — Form */}
      <div className="auth-right">
        <div className="auth-form-box">
          <h2>Đăng nhập</h2>
          <p className="auth-subtitle">
            Nhập thông tin tài khoản để tiếp tục sử dụng hệ thống.
          </p>

          <form className="auth-form" onSubmit={handleSubmit}>
            <div className="auth-form-group">
              <label htmlFor="username">Tên đăng nhập</label>
              <input
                id="username"
                type="text"
                name="username"
                value={formData.username}
                onChange={handleChange}
                placeholder="Nhập tên đăng nhập"
                autoComplete="username"
              />
            </div>

            <div className="auth-form-group">
              <label htmlFor="password">Mật khẩu</label>
              <input
                id="password"
                type="password"
                name="password"
                value={formData.password}
                onChange={handleChange}
                placeholder="Nhập mật khẩu"
                autoComplete="current-password"
              />
            </div>

            <button
              type="submit"
              className="auth-submit-btn"
              disabled={loading}
            >
              {loading ? "Đang đăng nhập..." : "🚀 Đăng nhập"}
            </button>
          </form>

          {message && (
            <div className="auth-alert-success" style={{ marginTop: "16px" }}>
              ✅ {message}
            </div>
          )}
          {error && (
            <div className="auth-alert-error" style={{ marginTop: "16px" }}>
              ⚠️ {error}
            </div>
          )}

          <div className="auth-divider" style={{ margin: "20px 0 16px" }}>
            hoặc
          </div>

          <p className="auth-alt-link">
            Chưa có tài khoản?{" "}
            <Link to="/register">Đăng ký miễn phí ngay →</Link>
          </p>

          <p style={{ marginTop: "12px", textAlign: "center" }}>
            <Link to="/" style={{ color: "#66756d", fontSize: "14px" }}>
              ← Về trang chủ
            </Link>
          </p>
        </div>
      </div>
    </div>
  );
}

export default Login;
